package com.example.saml;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.saml2.provider.service.authentication.OpenSamlAuthenticationProvider;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistrationRepository;
import org.springframework.security.saml2.provider.service.servlet.filter.*;
import org.springframework.security.web.SecurityFilterChain;
import org.w3c.dom.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.context.annotation.SessionScope;
import org.springframework.web.servlet.config.annotation.EnableWebMvc;

import javax.servlet.http.HttpSession;
import javax.xml.parsers.*;
import java.io.StringReader;

@SpringBootApplication
@EnableWebMvc
public class SamlServiceProviderApplication {

    public static void main(String[] args) {
        SpringApplication.run(SamlServiceProviderApplication.class, args);
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http, RelyingPartyRegistrationRepository relyingPartyRegistrationRepository) throws Exception {
        OpenSamlAuthenticationProvider openSamlAuthenticationProvider = new OpenSamlAuthenticationProvider();
        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/saml/**").permitAll()
                .anyRequest().authenticated())
            .saml2Login(saml2 -> saml2
                .relyingPartyRegistrationRepository(relyingPartyRegistrationRepository)
                .authenticationManager(authentication -> openSamlAuthenticationProvider.authenticate(authentication)));

        return http.build();
    }

    @RestController
    public static class SamlController {

        @PostMapping("/saml/SSO")
        public String sso(@RequestParam("SAMLResponse") String samlResponse, HttpSession session) {
            try {
                DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
                factory.setNamespaceAware(true);
                DocumentBuilder builder = factory.newDocumentBuilder();
                Document document = builder.parse(new InputSource(new StringReader(new String(Base64.getDecoder().decode(samlResponse)))));
                
                Element assertion = (Element) document.getElementsByTagNameNS("*", "Assertion").item(0);
                if (assertion != null) {
                    NodeList attributeNodes = assertion.getElementsByTagNameNS("*", "Attribute");

                    for (int i = 0; i < attributeNodes.getLength(); i++) {
                        Element attribute = (Element) attributeNodes.item(i);
                        String attributeName = attribute.getAttribute("Name");
                        NodeList valueNodes = attribute.getElementsByTagNameNS("*", "AttributeValue");
                        if (valueNodes.getLength() > 0) {
                            String value = valueNodes.item(0).getTextContent();
                            session.setAttribute(attributeName, value);
                        }
                    }
                    
                    session.setAttribute("authenticated", true);
                    return "Authentication Successful";
                }
            } catch (Exception e) {
                e.printStackTrace();
                return "Authentication Failed";
            }
            return "Authentication Failed";
        }
    }
}